#!/usr/bin/env python3
"""Block `pnpm test` (interactive watcher); steer Claude to `pnpm test:ci`."""
import json, sys

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    # Only run if the tool is Bash
    if ev.get("tool_name") != "Bash":
        return 0

    cmd = (ev.get("tool_input") or {}).get("command", "")

    # Check for the specific failure pattern: pnpm test without test:ci
    if cmd.strip().startswith("pnpm test") and "test:ci" not in cmd:
        print("REQUIRED FOLLOW-UP: Running `pnpm test` opens an interactive watcher and will time out. Use `pnpm test:ci` instead to run the non-interactive CI test suite.", file=sys.stderr)
        return 2

    return 0

if __name__ == "__main__":
    sys.exit(main())

