#!/usr/bin/env python3
"""After Edit/MultiEdit, if the old string contained a value, grep for all usages and feed the list back to Claude for verification."""
import json, subprocess, sys

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    if ev.get("tool_name") not in ("Edit", "MultiEdit"):
        return 0

    inp = ev.get("tool_input") or {}
    edits = inp.get("edits") or []

    # We are interested in the old string, as that is the value that was just replaced.
    old_strings = set()
    for e in edits:
        old_strings.add(e.get("old_string", ""))

    if not old_strings: 
        return 0

    # Use the first non-empty old string found for the search
    search_term = next((s for s in old_strings if s), None)
    if not search_term:
        return 0

    try:
        # Run grep across the project for the old string
        r = subprocess.run(
            ["grep", "-rn", "--include=*.ts", "--include=*.tsx", 
             "--include=*.js", "--include=*.jsx", search_term, "."],
            capture_output=True, text=True, timeout=10,
        )
        hits = [l for l in r.stdout.splitlines() if l][:20]

        if hits:
            # Imperative feedback via stderr
            print(f"REQUIRED FOLLOW-UP: The identifier '{search_term}' was edited. {len(hits)} stale references remain:", file=sys.stderr)
            for h in hits:
                print(f"  {h}", file=sys.stderr)
            print("Fix each reference to the new value, then summarize. Do not stop until done.", file=sys.stderr)
            return 2 # Block and provide feedback
    except Exception:
        # Handle subprocess errors gracefully
        pass
    return 0

if __name__ == "__main__":
    sys.exit(main())

